"use strict";parserFactory.register("wnmtl.com",()=>new WnmtlParser);class WnmtlParser extends Parser{constructor(){super()}getChapterUrls(e){let r=[...e.querySelectorAll("article div.t a")].filter(e=>"text-mutedxxx"!==e.parentElement.parentElement.className).map(e=>util.hyperLinkToChapter(e));return Promise.resolve(r)}findContent(e){return util.removeElements(e.querySelectorAll("div#ct div.article-social")),e.querySelector("div#ct")}extractTitleImpl(e){return e.querySelector("article header h2, article header h1")}findChapterTitle(e){return e.querySelector("h1.article-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"p.focus")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("article p.time, article p.note")]}}